$base = "$env:USERPROFILE\Desktop\AssetManagement"
$enc  = [System.Text.Encoding]::UTF8
Write-Host "Writing files..." -ForegroundColor Cyan

$p = "$base\AssetManagement.Web\Views\Requests\CreateSale.cshtml"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: CreateSale.cshtml" -ForegroundColor Green

$p = "$base\AssetManagement.Web\Views\Asset\FullDetails.cshtml"
$b = [System.Convert]::FromBase64String("")
[System.IO.File]::WriteAllBytes($p, $b)
Write-Host "  OK: FullDetails.cshtml" -ForegroundColor Green

cd $base
dotnet build 2>&1 | Select-Object -Last 4
if ($LASTEXITCODE -eq 0) { Write-Host "Build OK!" -ForegroundColor Green }